import React, { useEffect, useRef, useState } from 'react';

const COLORS = ['#22C55E', '#60A5FA', '#F59E0B', '#A78BFA', '#EF4444'];
const PARTICLE_COUNT = 150;
const GRAVITY = 0.15;
const FADE_DURATION = 3000;

function randomRange(min, max) {
  return Math.random() * (max - min) + min;
}

class Particle {
  constructor(width, height) {
    this.x = Math.random() * width;
    this.y = Math.random() * -height;
    this.size = randomRange(5, 12);
    this.color = COLORS[Math.floor(Math.random() * COLORS.length)];
    this.shape = Math.random() < 0.5 ? 'rect' : 'circle';
    this.vx = randomRange(-1, 1);
    this.vy = randomRange(1, 3);
    this.opacity = 1;
  }
  update() {
    this.vy += GRAVITY * 0.1;
    this.x += this.vx;
    this.y += this.vy;
    this.opacity -= 1 / (FADE_DURATION / 16.67);
  }
  isAlive(width, height) {
    return this.opacity > 0 && this.y - this.size < height && this.x + this.size > 0 && this.x - this.size < width;
  }
  draw(ctx) {
    ctx.globalAlpha = Math.max(this.opacity, 0);
    ctx.fillStyle = this.color;
    if (this.shape === 'rect') {
      ctx.fillRect(this.x, this.y, this.size, this.size);
    } else {
      ctx.beginPath();
      ctx.arc(this.x + this.size / 2, this.y + this.size / 2, this.size / 2, 0, Math.PI * 2);
      ctx.fill();
    }
    ctx.globalAlpha = 1;
  }
}

const TradeCelebration = ({ show, pnl }) => {
  const canvasRef = useRef(null);
  const animationFrameId = useRef(null);
  const [visible, setVisible] = useState(false);
  const particles = useRef([]);

  useEffect(() => {
    if (show && pnl > 0) {
      setVisible(true);
      const canvas = canvasRef.current;
      const ctx = canvas.getContext('2d');
      let width = window.innerWidth;
      let height = window.innerHeight;
      canvas.width = width;
      canvas.height = height;

      particles.current = [];
      for (let i = 0; i < PARTICLE_COUNT; i++) {
        particles.current.push(new Particle(width, height));
      }

      let startTime = null;

      const animate = (time) => {
        if (!startTime) startTime = time;
        const elapsed = time - startTime;

        ctx.clearRect(0, 0, width, height);

        particles.current.forEach((p) => {
          p.update();
        });
        particles.current = particles.current.filter((p) => p.isAlive(width, height));
        particles.current.forEach((p) => p.draw(ctx));

        if (elapsed < FADE_DURATION) {
          animationFrameId.current = requestAnimationFrame(animate);
        } else {
          setVisible(false);
        }
      };

      animationFrameId.current = requestAnimationFrame(animate);

      const handleResize = () => {
        width = window.innerWidth;
        height = window.innerHeight;
        canvas.width = width;
        canvas.height = height;
      };
      window.addEventListener('resize', handleResize);

      return () => {
        cancelAnimationFrame(animationFrameId.current);
        window.removeEventListener('resize', handleResize);
      };
    } else {
      setVisible(false);
    }
  }, [show, pnl]);

  if (!visible) return null;

  return (
    <div
      style={{
        position: 'fixed',
        inset: 0,
        backgroundColor: 'rgba(0,0,0,0.5)',
        fontFamily: "'JetBrains Mono', monospace",
        display: 'flex',
        flexDirection: 'column',
        justifyContent: 'center',
        alignItems: 'center',
        zIndex: 9999,
        pointerEvents: 'none',
        userSelect: 'none',
      }}
      aria-live="polite"
      aria-label="Trade celebration"
    >
      <canvas
        ref={canvasRef}
        style={{
          position: 'fixed',
          top: 0,
          left: 0,
          width: '100vw',
          height: '100vh',
          pointerEvents: 'none',
          userSelect: 'none',
          zIndex: 9998,
        }}
      />
      <div
        style={{
          position: 'relative',
          color: '#22C55E',
          fontSize: '6rem',
          fontWeight: '700',
          textShadow: '0 0 8px rgba(34,197,94,0.8)',
          pointerEvents: 'auto',
          userSelect: 'text',
          textAlign: 'center',
          lineHeight: 1.1,
        }}
      >
        ${pnl.toFixed(2)}
        <div
          style={{
            fontSize: '3rem',
            marginTop: '0.5rem',
            color: '#22C55E',
            textShadow: '0 0 6px rgba(34,197,94,0.7)',
          }}
        >
          Winner!
        </div>
      </div>
    </div>
  );
};

export default TradeCelebration;
